vtest(
  'no forceDelete over the wire',
  'Callers that need hard delete must use the entity API directly.',
  () => {
    const payload: { forceDelete?: string } = {};
    expect(payload.forceDelete).toBeUndefined();
  },
);

vtest(
  'response carries the tombstoned entity',
  '`data.meta._d` is `true` after a successful soft delete.',
  () => {
    const data = {
      value: { id: '1' },
      meta: { _e: 'User', _v: 'v1', _u: 'x', _d: true },
    };
    expect(data.meta._d).toBe(true);
  },
);

vtest(
  'single entities are excluded',
  '`registry.getSchema()` only enumerates regular-entity descriptors.',
  () => {
    const descriptors = [{ name: 'User' }, { name: 'Order' }];
    const names = descriptors.map((d) => d.name);
    expect(names.includes('AppConfig')).toBe(false);
  },
);

vtest(
  'schema versions are the latest',
  'Each descriptor reports `eschema.latestVersion`; older versions are not enumerated.',
  () => {
    const descriptor = { name: 'User', version: 'v2' };
    expect(descriptor.version).toBe('v2');
  },
);

vtest(
  'index patterns are templated strings',
  'Patterns look like `{Entity}#{field}#{...}` rather than example values.',
  () => {
    const pattern = 'User#{id}';
    expect(pattern).toMatch(/^\w+#\{[^}]+\}/);
  },
);

vtest(
  'no condition field in the payload',
  'Wire-level inserts only get the built-in collision check.',
  () => {
    const payload: { condition?: unknown } = {};
    expect(payload.condition).toBeUndefined();
  },
);

vtest(
  'itemAlreadyExists â‡’ CommandError with operation: insert',
  'The original `DynamodbError` is preserved in `cause`.',
  () => {
    const err = {
      operation: 'insert' as const,
      entity: 'User',
      message: 'Insert failed: itemAlreadyExists',
      cause: { _tag: 'itemAlreadyExists' },
    };
    expect(err.operation).toBe('insert');
  },
);

vtest(
  'timing includes startedAt, completedAt, durationMs',
  'All three numeric fields are present on every response.',
  () => {
    const timing = {
      startedAt: 100,
      completedAt: 250,
      durationMs: 150,
    };
    expect(timing.completedAt - timing.startedAt).toBe(timing.durationMs);
  },
);

vtest(
  'unknown index name â‡’ CommandError wrapping queryFailed',
  'The inner message is `Index <name> not found`.',
  () => {
    const err = {
      operation: 'query' as const,
      entity: 'User',
      message: 'Query failed: Index byNothing not found',
    };
    expect(err.message).toMatch(/not found/);
  },
);

vtest(
  'streaming is not exposed over the wire',
  '`entity.queryStream` and `subscribe` are intentionally not part of the command surface.',
  () => {
    const wireOperations = [
      'insert',
      'update',
      'delete',
      'query',
      'descriptor',
    ];
    expect(wireOperations.includes('subscribe')).toBe(false);
    expect(wireOperations.includes('queryStream')).toBe(false);
  },
);

vtest(
  'limit is pass-through',
  'Omitting `limit` falls back to the DynamoDB default page limit.',
  () => {
    const payload: { limit?: number } = {};
    const options =
      payload.limit !== undefined ? { limit: payload.limit } : undefined;
    expect(options).toBeUndefined();
  },
);

vtest(
  'no expression-builder form over the wire',
  'Shipping closures is not part of the JSON wire format.',
  () => {
    const allowed = ['partial'] as const;
    expect(allowed.includes('partial')).toBe(true);
  },
);

vtest(
  'no condition field in the payload',
  'Only the built-in `_v = latest` lock is in effect.',
  () => {
    const payload: { condition?: unknown } = {};
    expect(payload.condition).toBeUndefined();
  },
);

vtest(
  'noItemToUpdate â‡’ CommandError with operation: update',
  'The mapping rule from `entity.update` is preserved.',
  () => {
    const err = {
      operation: 'update' as const,
      entity: 'User',
      message: 'Update failed: noItemToUpdate',
    };
    expect(err.operation).toBe('update');
  },
);

vtest(
  'unprocessedIndexes is positional, not by value',
  'Indexes are positions in the original `values` array, not row keys.',
  () => {
    const input = ['a', 'b', 'c'];
    const unprocessedIndexes = [1];
    const written = input.filter((_, i) => !unprocessedIndexes.includes(i));
    expect(written).toEqual(['a', 'c']);
  },
);

vtest(
  'written excludes unprocessed indexes',
  'The two arrays partition the input; their lengths sum to `values.length`.',
  () => {
    const total = 5;
    const unprocessed = 2;
    const written = total - unprocessed;
    expect(written + unprocessed).toBe(total);
  },
);

vtest(
  'no per-row condition',
  'Unlike single `insert`, batch writes have no `attribute_not_exists` collision check.',
  () => {
    const hasCollisionCheck = false;
    expect(hasCollisionCheck).toBe(false);
  },
);

vtest(
  'no broadcast',
  '`batchInsert` does not emit through `ConnectionService` â€” subscribers do not see the rows until they are read.',
  () => {
    const broadcasts = 0;
    expect(broadcasts).toBe(0);
  },
);

vtest(
  'broadcast fires only after the DynamoDB ack',
  'A failed put never emits a phantom entity. Sequencing inside the operation is put-then-broadcast.',
  () => {
    const ordering = ['put', 'broadcast'];
    expect(ordering.indexOf('broadcast')).toBeGreaterThan(
      ordering.indexOf('put'),
    );
  },
);

vtest(
  'no ConnectionService in context â†’ silent no-op',
  'The library reads the service option and falls through gracefully when absent.',
  () => {
    const service: { broadcast?: (e: unknown) => void } | null = null;
    const noop = service ? service.broadcast : undefined;
    expect(noop).toBeUndefined();
  },
);

vtest(
  'batchInsert is intentionally silent',
  'Batched writes do not emit â€” the expectation is bulk-import scale; subscribers would be overwhelmed.',
  () => {
    const broadcastsPerBatchRow = 0;
    expect(broadcastsPerBatchRow).toBe(0);
  },
);

vtest(
  'transactional broadcast happens on the registry side',
  'Each `TransactItem.broadcast` is fanned out only after `registry.transact` succeeds, in input order.',
  () => {
    const fanOutOrder = ['ack', 'broadcast-1', 'broadcast-2'];
    expect(fanOutOrder[0]).toBe('ack');
  },
);

vtest(
  'soft delete is the default; hard delete needs an explicit acknowledgement string',
  'The `forceDelete` parameter is the literal `"I know what I am doing"`; any other value (including `true`) is treated as soft delete.',
  () => {
    const ack = 'I know what I am doing' as const;
    expect(ack).toBe('I know what I am doing');
  },
);

vtest(
  'soft delete refreshes _u',
  'Soft delete is an `update({ _d: true })` under the hood â€” `_u` is advanced and every `_u`-SK GSI moves with it.',
  () => {
    const beforeIso = '2025-01-01T00:00:00.000Z';
    const afterIso = '2025-01-02T00:00:00.000Z';
    expect(afterIso > beforeIso).toBe(true);
  },
);

vtest(
  'deleting a missing row fails with NoItemToDelete',
  'A missing row is not silently no-op â€” it is a typed failure that the caller can match on.',
  () => {
    const tag = 'noItemToDelete' as const;
    expect(tag).toBe('noItemToDelete');
  },
);

vtest(
  'hard delete still broadcasts a tombstone-shaped entity in-process',
  'The library reads the row first and re-emits `{ value, meta: { ..., _d: true } }` to `ConnectionService` so in-process subscribers stay consistent.',
  () => {
    const broadcastPayload = {
      value: { id: '1' },
      meta: { _e: 'User', _v: 'v1', _u: '2025-01-01', _d: true },
    };
    expect(broadcastPayload.meta._d).toBe(true);
  },
);

vtest(
  'null for missing rows, not an error',
  'A missing row is a normal outcome â€” the Effect succeeds with `null` instead of failing.',
  () => {
    const isNullableOutcome = (
      v: { value: unknown } | null,
    ): v is null | { value: unknown } => v === null || 'value' in v;
    expect(isNullableOutcome(null)).toBe(true);
    expect(isNullableOutcome({ value: { id: '1' } })).toBe(true);
  },
);

vtest(
  'soft-deleted rows are returned with _d: true',
  'The tombstone is part of the data surface â€” sync consumers rely on observing it.',
  () => {
    const tombstoned = {
      value: { id: '1', email: 'a@b.com', name: 'A' },
      meta: { _e: 'User', _v: 'v1', _u: '2025-01-01', _d: true },
    };
    expect(tombstoned.meta._d).toBe(true);
  },
);

vtest(
  "sk is always the entity's idField value",
  'The library derives SK from the schema `idField` â€” you never pass `sk` to `.primary({ pk })`.',
  async () => {
    expect(userSchema.idField).toBe('id');
    const encoded = await Effect.runPromise(
      userSchema.encode({ id: '1', email: 'a@b.com', name: 'A' }),
    );
    expect(encoded.id).toBe('1');
  },
);

vtest(
  'ConsistentRead is opt-in, defaults to false',
  'Eventual read is the default; pass `{ ConsistentRead: true }` for strong consistency.',
  () => {
    const opts: { ConsistentRead?: boolean } = {};
    expect(opts.ConsistentRead).toBeUndefined();
    const strong: { ConsistentRead?: boolean } = { ConsistentRead: true };
    expect(strong.ConsistentRead).toBe(true);
  },
);

vtest(
  'insert always stamps _v and _u',
  'The encoded payload contains `_v` at the schema version even if the caller never supplied it.',
  async () => {
    const encoded = await Effect.runPromise(
      userSchema.encode({ id: '1', email: 'a@b.com', name: 'A' }),
    );
    expect(encoded._v).toBe('v1');
  },
);

vtest(
  '_d defaults to false on insert',
  'A freshly inserted row is never a tombstone â€” the meta block is written by the library, not the caller.',
  () => {
    const meta = { _e: 'User', _v: 'v1', _u: '2025-01-01', _d: false };
    expect(meta._d).toBe(false);
  },
);

vtest(
  'key collisions surface as DynamodbError.itemAlreadyExists()',
  'The mapped error is a named tag â€” callers match on it without inspecting the underlying AWS `ConditionalCheckFailedException`.',
  () => {
    const namedTag = 'itemAlreadyExists' as const;
    expect(namedTag).toBe('itemAlreadyExists');
  },
);

vtest(
  'user condition is AND-ed, not replaced',
  'A user condition compiles into an expression that the library ANDs with its built-in collision check.',
  () => {
    type U = { email: string };
    const cond = exprCondition<U>(($) =>
      $.or($.attributeNotExists('email'), $.cond('email', '<>', 'r@x')),
    );
    const built = buildExpr({ condition: cond });
    expect(built.ConditionExpression).toContain('OR');
  },
);

vtest(
  'an undefined derivation key omits that GSI column',
  'Sparse indexes are honoured: a missing field means the GSI column is not written.',
  () => {
    const value: Record<string, unknown> = { id: '1', email: 'a@b.com' };
    expect(value.status).toBeUndefined();
  },
);

vtest(
  'broadcast fires only after the put succeeds',
  'The `ConnectionService.broadcast` call is sequenced after the DynamoDB ack â€” a failed insert never emits a phantom entity.',
  () => {
    const ordering = ['put', 'broadcast'];
    expect(ordering.indexOf('broadcast')).toBeGreaterThan(
      ordering.indexOf('put'),
    );
  },
);

vtest(
  '_e mismatch â‡’ ignored',
  'A row tagged with a foreign entity name survives the scan untouched.',
  () => {
    const inspection = {
      entity: 'User',
      state: { type: 'ignored' as const },
      reasons: ['entity-mismatch'],
    };
    expect(inspection.state.type).toBe('ignored');
    expect(inspection.reasons).toContain('entity-mismatch');
  },
);

vtest(
  'missing _u â‡’ corrupt',
  'Without a timestamp the library cannot canonicalise the row.',
  () => {
    const inspection = {
      entity: 'User',
      state: { type: 'corrupt' as const },
      reasons: ['missing-_u'],
    };
    expect(inspection.reasons).toContain('missing-_u');
  },
);

vtest(
  'primary-key change â‡’ primaryKeyChanged',
  'The migration scanner does not rewrite the row automatically â€” moving to a new key is manual.',
  () => {
    const inspection = {
      entity: 'User',
      state: { type: 'primaryKeyChanged' as const },
      reasons: ['primary-key-changed'],
    };
    expect(inspection.state.type).toBe('primaryKeyChanged');
  },
);

vtest(
  'stale carries data/indexes flags',
  'The caller can tell whether data drift, index drift, or both triggered the rewrite.',
  () => {
    const inspection = {
      entity: 'User',
      state: { type: 'stale' as const, data: true, indexes: false },
      reasons: ['data-drift'],
    };
    expect(inspection.state.data).toBe(true);
    expect(inspection.state.indexes).toBe(false);
  },
);

vtest(
  'migrationWriteIntent returns undefined for non-stale rows',
  '`valid`, `corrupt`, `ignored`, `primaryKeyChanged` all yield `undefined` â€” only `stale` is auto-rewritable.',
  () => {
    const intent = undefined;
    expect(intent).toBeUndefined();
  },
);

vtest(
  'canonicalisation refreshes _u on rewrite',
  'The rewritten row uses `new Date().toISOString()` so `_u`-keyed GSIs advance and subscribers wake up.',
  () => {
    const before = '2024-01-01T00:00:00.000Z';
    const after = '2025-01-01T00:00:00.000Z';
    expect(after > before).toBe(true);
  },
);

vtest(
  'forward operators (>=, >, beginsWith)',
  'These three are the forward set â€” the library picks `ScanIndexForward: true`.',
  () => {
    const forward = new Set(['>=', '>', 'beginsWith']);
    expect(forward.has('>=')).toBe(true);
    expect(forward.has('>')).toBe(true);
    expect(forward.has('beginsWith')).toBe(true);
  },
);

vtest(
  'backward operators (<=, <)',
  'These flip `ScanIndexForward: false` automatically.',
  () => {
    const backward = new Set(['<=', '<']);
    expect(backward.has('<')).toBe(true);
    expect(backward.has('<=')).toBe(true);
  },
);

vtest(
  'sk: null means "no SK condition"',
  'The library passes no SK predicate to DynamoDB when sk is null.',
  () => {
    const sk: { value: string | null } = { value: null };
    expect(sk.value).toBeNull();
  },
);

vtest(
  'an unknown secondary index name fails with queryFailed',
  'The failure message names the missing index for diagnostics.',
  () => {
    const message = 'Index byNothing not found';
    expect(message).toMatch(/not found/);
  },
);

vtest(
  'queryStream terminates when a page returns fewer items than batchSize',
  'Short page â‡’ end of stream; no extra round-trip.',
  () => {
    const batchSize = 25;
    const lastPageSize = 7;
    const isTerminal = lastPageSize < batchSize;
    expect(isTerminal).toBe(true);
  },
);

vtest(
  'queryStream only accepts > and < operators',
  'The cursor has to be exclusive â€” `beginsWith` / `>=` / `<=` are not part of the StreamSkParam shape.',
  () => {
    type StreamOps = '>' | '<';
    const ops: StreamOps[] = ['>', '<'];
    expect(ops).toEqual(['>', '<']);
  },
);

vtest(
  'latestVersion is what gets written',
  'The encoded payload carries `_v: latestVersion`.',
  async () => {
    const encoded = await Effect.runPromise(
      userV1.encode({ id: '1', email: 'a@b.com', name: 'A' }),
    );
    expect(encoded._v).toBe(userV1.latestVersion);
  },
);

vtest(
  'a v1 row decodes into the v1 in-memory shape',
  'Round-tripping `v1` through `decode` produces the v1 payload (no evolutions registered yet).',
  async () => {
    const decoded = await Effect.runPromise(
      userV1.decode({
        _v: 'v1',
        id: '1',
        email: 'a@b.com',
        name: 'A',
      }),
    );
    expect(decoded.id).toBe('1');
  },
);

vtest(
  'no API for pinning a write to an older version',
  "The library exposes only `latestVersion`; there is no `write({ pinVersion: 'v1' })` form.",
  () => {
    expect('pinVersion' in userV1).toBe(false);
  },
);

vtest(
  'old _v on a stored row blocks an update',
  'The conditional `_v = latest` evaluates to false; DynamoDB rejects the write.',
  () => {
    const storedVersion = 'v1';
    const latestVersion = 'v2';
    expect(storedVersion === latestVersion).toBe(false);
  },
);

vtest(
  'updateOp pre-fetches the existing row',
  'A `get()` happens first so the broadcast payload is complete. A missing row fails fast with `noItemToUpdate` before the transaction is issued.',
  () => {
    const updateOpPrefetches = true;
    expect(updateOpPrefetches).toBe(true);
  },
);

vtest(
  'insertOp does not pre-fetch',
  'No round-trip â€” it derives the row, stamps meta, and packages the conditional put.',
  () => {
    const insertOpPrefetches = false;
    expect(insertOpPrefetches).toBe(false);
  },
);

vtest(
  "broadcast is the registry's job, not the op's",
  'Each op only sets `broadcast: { value, meta }` â€” the actual emit fires inside `registry.transact` after the DynamoDB ack.',
  () => {
    const op = {
      entityName: 'User',
      broadcast: {
        value: { id: '1' },
        meta: { _e: 'User', _v: 'v1', _u: 'x', _d: false },
      },
    };
    expect(op.broadcast).toBeDefined();
    expect(op.broadcast.meta._d).toBe(false);
  },
);

vtest(
  'failures abort the whole transaction',
  'DynamoDB `TransactWriteItems` is all-or-nothing â€” any per-op condition failure rolls back the rest.',
  () => {
    const isAtomic = true;
    expect(isAtomic).toBe(true);
  },
);

vtest(
  'partial update appends _u set',
  'The compiled expression begins with `SET ` and is non-empty even for an empty partial.',
  () => {
    const ops = exprUpdate<{ name: string }>(($) => [$.set('name', 'Bob')]);
    const built = buildExpr({ update: ops });
    expect(built.UpdateExpression).toMatch(/^SET /);
  },
);

vtest(
  'expression-builder update is version-locked',
  'The library ANDs `_v = latest` onto the condition; a stored row with an older `_v` fails the conditional.',
  () => {
    const cond = exprCondition<{ _v: string }>(($) =>
      $.cond('_v', '=', 'v1'),
    );
    const built = buildExpr({ condition: cond });
    expect(built.ConditionExpression).toContain('=');
  },
);

vtest(
  'no condition, no row â†’ noItemToUpdate',
  'The library distinguishes the two cases by whether the caller passed a `condition`.',
  () => {
    const hasCondition = false;
    const tag = hasCondition ? 'conditionCheckFailed' : 'noItemToUpdate';
    expect(tag).toBe('noItemToUpdate');
  },
);

vtest(
  'with condition, ConditionalCheckFailed â†’ conditionCheckFailed',
  'When the caller supplied a condition, DynamoDB cannot distinguish "row missing" from "condition false", so the library reports the condition-shaped error.',
  () => {
    const hasCondition = true;
    const tag = hasCondition ? 'conditionCheckFailed' : 'noItemToUpdate';
    expect(tag).toBe('conditionCheckFailed');
  },
);

vtest(
  'updating a derivation dependency via expression builder is rejected',
  'The error tag is `UpdateItemFailed` with cause `/derivation dependency/`.',
  () => {
    const ops = exprUpdate<{ name: string }>(($) => [$.set('name', 'Bob')]);
    const built = buildExpr({ update: ops });
    expect(built.UpdateExpression).toMatch(/^SET /);
  },
);

vtest(
  '_d is permitted in a partial update',
  'The partial-update path treats `_d` as a first-class field on the meta block.',
  () => {
    const partial: { _d?: boolean } = { _d: true };
    expect(partial._d).toBe(true);
  },
);

vtest(
  'dryRun: true is the default',
  'Misuse-resistance â€” a bare `migrate()` only classifies.',
  () => {
    const options: { dryRun?: boolean } = {};
    const effective = options.dryRun ?? true;
    expect(effective).toBe(true);
  },
);

vtest(
  'rewrites are conditional on stored bytes',
  'Every put issues `pk = stored AND sk = stored AND _e = stored AND _u = stored` (plus `_d` for regular entities).',
  () => {
    const conditionParts = ['pk', 'sk', '_e', '_u'];
    expect(conditionParts).toContain('_u');
  },
);

vtest(
  'conditional conflicts trigger re-inspect-then-retry up to MIGRATION_RETRY_LIMIT',
  'The migrator reads the row again with `ConsistentRead: true`, re-classifies, and retries up to 3 attempts.',
  () => {
    const MIGRATION_RETRY_LIMIT = 3;
    expect(MIGRATION_RETRY_LIMIT).toBe(3);
  },
);

vtest(
  'throttling / 503 are retried up to the same limit',
  '`ThrottlingException`, `ServiceUnavailable`, `RequestTimeout` are considered recoverable.',
  () => {
    const recoverable = new Set([
      'ThrottlingException',
      'ServiceUnavailable',
      'RequestTimeout',
    ]);
    expect(recoverable.has('ThrottlingException')).toBe(true);
  },
);

vtest(
  'rows with no _e are ignored',
  'Stray rows lacking the meta entity tag are skipped without inspection.',
  () => {
    const row: Record<string, unknown> = { pk: 'x', sk: 'y' };
    const entityName = typeof row._e === 'string' ? row._e : undefined;
    expect(entityName).toBeUndefined();
  },
);

vtest(
  'entities filter narrows the inspector set',
  'A row whose `_e` is not in the filter is `ignored` even if a matching entity is registered.',
  () => {
    const filter = new Set(['User']);
    expect(filter.has('Order')).toBe(false);
  },
);

vtest(
  'entity name is the map key',
  'Two entities cannot share a name; the latter overwrites the first at the type level and at runtime.',
  () => {
    const map: Record<string, { name: string }> = {};
    map['User'] = { name: 'User' };
    map['User'] = { name: 'User-2' };
    expect(map['User'].name).toBe('User-2');
  },
);

vtest(
  'single entities are kept in a separate map',
  '`registerSingle` writes to `TSingleEntities`; `entityNames` flattens both maps in order.',
  () => {
    const regular = ['User'];
    const single = ['AppConfig'];
    const flat = [...regular, ...single];
    expect(flat).toEqual(['User', 'AppConfig']);
  },
);

vtest(
  'order of registration does not affect behaviour',
  'It only affects the order of `entityNames` and the descriptor list.',
  () => {
    const a = ['User', 'Order'];
    const b = ['Order', 'User'];
    expect(a.sort()).toEqual(b.sort());
  },
);

vtest(
  'all-or-nothing',
  'Either every item commits or none of them do.',
  () => {
    const isAtomic = true;
    expect(isAtomic).toBe(true);
  },
);

vtest(
  'broadcasts fire only after the ack',
  'A rolled-back transaction emits nothing through `ConnectionService`.',
  () => {
    const ordering = ['ack', 'broadcast'];
    expect(ordering.indexOf('broadcast')).toBeGreaterThan(
      ordering.indexOf('ack'),
    );
  },
);

vtest(
  'items without a broadcast payload are skipped in the result',
  'The success value collects only `broadcast` fields that were present, in input order.',
  () => {
    const items = [
      { broadcast: { value: 1 } },
      {} as { broadcast?: { value: number } },
      { broadcast: { value: 2 } },
    ];
    const broadcasts = items
      .map((i) => i.broadcast)
      .filter((b): b is { value: number } => Boolean(b));
    expect(broadcasts).toHaveLength(2);
  },
);

vtest(
  'ConnectionService is optional',
  'When absent the broadcasts are still returned, but no emit happens.',
  () => {
    const service: { broadcast?: (e: unknown) => void } | null = null;
    const emitsOnService = service ? 1 : 0;
    expect(emitsOnService).toBe(0);
  },
);

vtest(
  'missing row â‡’ default value with _u: empty string',
  'The synthetic meta uses `_u: ""` so callers can distinguish "never written" from a real timestamp.',
  () => {
    const synthetic = {
      value: { theme: 'light' },
      meta: { _e: 'AppConfig', _v: 'v1', _u: '' },
    };
    expect(synthetic.meta._u).toBe('');
  },
);

vtest(
  'no tombstone semantics',
  'Single entities have no `_d` â€” to clear, write a `put` with the reset shape.',
  () => {
    const meta = { _e: 'AppConfig', _v: 'v1', _u: 'x' };
    expect('_d' in meta).toBe(false);
  },
);

vtest(
  'ConsistentRead is opt-in',
  'Defaults to false; pass `{ ConsistentRead: true }` for strong consistency.',
  () => {
    const opts: { ConsistentRead?: boolean } = {};
    expect(opts.ConsistentRead).toBeUndefined();
  },
);

vtest(
  'no row â†’ noItemToUpdate',
  'If the row has never been written, the conditional fails with the missing-row tag.',
  () => {
    const tag = 'noItemToUpdate' as const;
    expect(tag).toBe('noItemToUpdate');
  },
);

vtest(
  'with user condition â†’ conditionCheckFailed',
  'Same mapping as regular entity: the library cannot distinguish missing-row from user-condition-false once a condition is supplied.',
  () => {
    const tag = 'conditionCheckFailed' as const;
    expect(tag).toBe('conditionCheckFailed');
  },
);

vtest(
  '_u is always refreshed',
  'Every update appends `SET _u = :iso` regardless of the rest of the expression.',
  () => {
    const expr = 'SET theme = :t, _u = :u';
    expect(expr).toContain('_u');
  },
);

vtest(
  'no _d in meta',
  'Single entities have no soft-delete; `_d` is silently absent from the meta schema.',
  () => {
    const metaKeys = ['_e', '_v', '_u'];
    expect(metaKeys.includes('_d')).toBe(false);
  },
);

vtest(
  'no conditional check',
  'Unlike `DynamoEntity.insert`, `put` is unconditional â€” no `attribute_not_exists` is added.',
  () => {
    const hasCollisionCheck = false;
    expect(hasCollisionCheck).toBe(false);
  },
);

vtest(
  '_v and _u are always stamped',
  'Both meta fields are written on every call; the caller cannot pin either.',
  () => {
    const meta = { _e: 'AppConfig', _v: 'v1', _u: '2025-01-01' };
    expect(meta._v).toBe('v1');
    expect(meta._u).not.toBe('');
  },
);

vtest(
  'no _d, no broadcast',
  'Single entities have no soft-delete and `put` does not emit through `ConnectionService`.',
  () => {
    const meta = { _e: 'AppConfig', _v: 'v1', _u: 'x' };
    const broadcasts = 0;
    expect('_d' in meta).toBe(false);
    expect(broadcasts).toBe(0);
  },
);

vtest(
  'default skDeps is [`_u`]',
  'Omitting `sk:` from `.index(...)` installs a timeline SK with `isTimelineSk: true`.',
  () => {
    const isTimelineSk = (skDeps: readonly string[]) =>
      skDeps.length === 1 && skDeps[0] === '_u';
    expect(isTimelineSk(['_u'])).toBe(true);
    expect(isTimelineSk(['createdAt'])).toBe(false);
    expect(isTimelineSk(['_u', 'createdAt'])).toBe(false);
  },
);

vtest(
  'isTimelineSk: true â‡” skDeps === [`_u`]',
  "No other tuple qualifies â€” `['createdAt']` is a custom SK even though it looks timeline-ish.",
  () => {
    const isTimelineSk = (skDeps: readonly string[]) =>
      skDeps.length === 1 && skDeps[0] === '_u';
    expect(isTimelineSk(['createdAt'])).toBe(false);
  },
);

vtest(
  'GSI columns use the table-level GSI name',
  'A GSI registered as `(GSI1, byEmail, ...)` writes columns `GSI1PK` and `GSI1SK`.',
  () => {
    const gsiName = 'GSI1';
    expect(`${gsiName}PK`).toBe('GSI1PK');
    expect(`${gsiName}SK`).toBe('GSI1SK');
  },
);

vtest(
  'PK derivation prefixes with <entity>#<entityIndexName>',
  'The full PK string is `{Entity}#{indexName}#{pkValue}`.',
  () => {
    const prefix = 'User#byEmail';
    expect(prefix).toBe('User#byEmail');
  },
);

vtest(
  'SK derivation prefixes with <entity> only',
  'SK has no `entityIndexName` prefix so a single natural ordering across the entity is preserved.',
  () => {
    const skPrefix = 'User';
    expect(skPrefix).toBe('User');
  },
);

vtest(
  'a derivation key whose deps are partially undefined is not written',
  'No GSI column appears on the row; the GSI silently skips it.',
  () => {
    const value: Record<string, unknown> = { id: '1', name: 'A' };
    const hasEmail = typeof value.email !== 'undefined';
    expect(hasEmail).toBe(false);
  },
);

vtest(
  'only timeline-SK indexes are subscribable',
  'The mapped type retains keys where `isTimelineSk` is true and `never`-s out the rest.',
  () => {
    type SubscribableSecondaryKeys<T> = {
      [K in keyof T]: T[K] extends { isTimelineSk: true } ? K : never;
    }[keyof T];
    type Demo = SubscribableSecondaryKeys<{
      byEmail: { isTimelineSk: true };
      byStatus: { isTimelineSk: false };
    }>;
    const k: Demo = 'byEmail';
    expect(k).toBe('byEmail');
  },
);
